const FONTS={primary:'Outfit, sans-serif'};const COLORS={text:{dark:'#111827',medium:'#4B5563',light:'#9CA3AF',muted:'#D1D5DB'},border:'#E5E7EB',grid:'#f3f4f6',primary:'#8B5CF6',primaryLight:'#C4B5FD',primaryBg:'#EDE9FE',success:'#10B981',white:'#ffffff'};const formatCurrency=(value)=>{return new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',minimumFractionDigits:0}).format(value);};const getCommonTooltipOptions=()=>({backgroundColor:COLORS.white,titleColor:'#1F2937',bodyColor:COLORS.text.medium,borderColor:COLORS.border,borderWidth:1,padding:12,titleFont:{family:FONTS.primary,size:14,weight:'bold'},bodyFont:{family:FONTS.primary,size:13,weight:'bold'},cornerRadius:12,});const getCommonGridOptions=()=>({color:COLORS.grid,borderDash:[5,5],drawBorder:false});const getCommonTickOptions=()=>({font:{family:FONTS.primary,size:11},color:COLORS.text.light});async function fetchChartData(url){if(!url)return null;try{const response=await fetch(url);return await response.json();}catch(error){console.error('Error fetching chart data:',error);return null;}}
const centerTextPlugin={id:'centerText',beforeDraw:(chart)=>{if(chart.config.type!=='doughnut')return;const{width,height,ctx,data}=chart;ctx.restore();ctx.font=`500 13px ${FONTS.primary}`;ctx.textBaseline='middle';ctx.fillStyle=COLORS.text.light;const text1='Gastos de este mes';const textX1=Math.round((width-ctx.measureText(text1).width)/2);const textY1=height/2-15;ctx.fillText(text1,textX1,textY1);ctx.font=`bold 28px ${FONTS.primary}`;ctx.fillStyle=COLORS.text.dark;let sum=0;if(data.datasets?.[0]?.data){sum=data.datasets[0].data.reduce((a,b)=>Number(a)+Number(b),0);}
const formatter=new Intl.NumberFormat('en-US',{style:'currency',currency:'USD'});const parts=formatter.formatToParts(sum);let integerPart='';let decimalPart='';parts.forEach(p=>{if(p.type==='decimal'||p.type==='fraction')decimalPart+=p.value;else integerPart+=p.value;});const textX2=Math.round((width-ctx.measureText(integerPart+decimalPart).width)/2);const textY2=height/2+20;ctx.fillText(integerPart,textX2,textY2);const intWidth=ctx.measureText(integerPart).width;ctx.fillStyle=COLORS.text.muted;ctx.font=`bold 24px ${FONTS.primary}`;ctx.fillText(decimalPart,textX2+intWidth,textY2+1);ctx.save();}};async function initGastosChart(){const canvas=document.getElementById('gastosPorCategoriaChart');if(!canvas)return;const data=await fetchChartData(canvas.dataset.url);if(!data)return;const palette=[COLORS.primary,'#C4B5FD','#EDE9FE','#4B5563','#9CA3AF','#E5E7EB','#6D28D9','#A78BFA','#374151','#D1D5DB'];const backgroundColors=data.labels.map((_,i)=>palette.at(i%palette.length));new Chart(canvas,{type:'doughnut',plugins:[centerTextPlugin],data:{labels:data.labels,datasets:[{data:data.data,backgroundColor:backgroundColors,borderWidth:4,borderColor:COLORS.white,borderRadius:20,hoverOffset:6}]},options:{responsive:true,maintainAspectRatio:false,layout:{padding:20},cutout:'80%',rotation:180,plugins:{legend:{display:false},tooltip:{...getCommonTooltipOptions(),displayColors:false,yAlign:'bottom',callbacks:{title:()=>null,label:(context)=>{const sum=context.dataset.data.reduce((a,b)=>Number(a)+Number(b),0);const percentage=Math.round((context.parsed*100)/sum);return`${percentage}% ${formatCurrency(context.parsed)}`;}}},datalabels:{display:false}}}});renderGastosLegend(data.labels,backgroundColors);}
function renderGastosLegend(labels,colors){const container=document.getElementById('gastosLegend');if(!container)return;container.replaceChildren();labels.forEach((label,i)=>{const div=document.createElement('div');div.className='flex items-center gap-2 mb-2 w-auto min-w-[30%]';const colorSpan=document.createElement('span');colorSpan.className='w-2.5 h-2.5 rounded-full';colorSpan.style.backgroundColor=colors.at(i);const labelSpan=document.createElement('span');labelSpan.className='text-xs font-semibold text-gray-700';labelSpan.textContent=label;div.appendChild(colorSpan);div.appendChild(labelSpan);container.appendChild(div);});}
function initSavingsGrowthChart(){const canvas=document.getElementById('savingsGrowthChart');if(!canvas)return;const{labels,data}=getSavingsData();const dataLastMonth=data.map(v=>Number(v)*(0.7+Math.random()*0.4));const ctx=canvas.getContext('2d');const gradient=ctx.createLinearGradient(0,0,0,300);gradient.addColorStop(0,'rgba(139, 92, 246, 0.4)');gradient.addColorStop(1,'rgba(139, 92, 246, 0.05)');new Chart(canvas,{type:'line',data:{labels,datasets:[{label:'This month',data:data,borderColor:COLORS.primary,backgroundColor:gradient,borderWidth:3,fill:true,tension:0.4,pointBackgroundColor:COLORS.white,pointBorderColor:COLORS.primary,pointBorderWidth:2,pointRadius:4,pointHoverRadius:6,pointHoverBorderWidth:3},{label:'Same period last month',data:dataLastMonth,borderColor:COLORS.primaryLight,borderWidth:2,borderDash:[5,5],fill:false,tension:0.4,pointRadius:0,pointHoverRadius:4}]},options:{responsive:true,maintainAspectRatio:false,layout:{padding:{top:20,right:20,left:10,bottom:10}},interaction:{mode:'index',intersect:false},scales:{y:{beginAtZero:true,suggestedMax:Math.max(...data)*1.2,grid:getCommonGridOptions(),ticks:{...getCommonTickOptions(),callback:(value)=>formatCurrency(value)}},x:{grid:{display:false},ticks:getCommonTickOptions()}},plugins:{legend:{display:false},tooltip:{...getCommonTooltipOptions(),displayColors:true,callbacks:{label:(context)=>`${context.dataset.label}: ${formatCurrency(context.parsed.y)}`}}}}});}
function getSavingsData(){const labelsScript=document.getElementById('savings-labels-data');const valuesScript=document.getElementById('savings-values-data');if(labelsScript&&valuesScript){return{labels:JSON.parse(labelsScript.textContent),data:JSON.parse(valuesScript.textContent)};}
return{labels:['1 Jul','3 Jul','5 Jul','7 Jul','9 Jul','11 Jul','13 Jul','15 Jul','17 Jul'],data:[16000,15000,9500,13000,18500,12500,16000,13000,17500]};}
async function initBudgetVsActualChart(){const canvas=document.getElementById('budgetVsActualChart');if(!canvas)return;const data=await fetchChartData(canvas.dataset.url);if(!data)return;new Chart(canvas,{type:'bar',data:{labels:data.labels,datasets:[{label:'Gasto Real',data:data.real,backgroundColor:COLORS.primary,borderRadius:4,barPercentage:0.6,categoryPercentage:0.7},{label:'Presupuesto',data:data.presupuestado,backgroundColor:COLORS.primaryBg,borderRadius:4,barPercentage:0.6,categoryPercentage:0.7}]},options:{responsive:true,maintainAspectRatio:false,layout:{padding:{top:20,right:10,left:10,bottom:0}},scales:{x:{stacked:false,grid:{display:false},ticks:getCommonTickOptions()},y:{stacked:false,beginAtZero:true,grid:getCommonGridOptions(),ticks:{...getCommonTickOptions(),callback:(value)=>formatCurrency(value)}}},plugins:{legend:{display:false},tooltip:{...getCommonTooltipOptions(),callbacks:{label:(context)=>`${context.dataset.label}: ${formatCurrency(context.parsed.y)}`}}}}});}
async function initInversionesChart(){const canvas=document.getElementById('investmentLineChart');if(!canvas)return;const data=await fetchChartData(canvas.dataset.url);if(!data)return;const ctx=canvas.getContext('2d');const gradient=ctx.createLinearGradient(0,0,0,400);gradient.addColorStop(0,'rgba(16, 185, 129, 0.2)');gradient.addColorStop(1,'rgba(16, 185, 129, 0)');new Chart(canvas,{type:'line',data:{labels:data.labels,datasets:[{label:'Capital',data:data.data,fill:true,borderColor:COLORS.success,backgroundColor:gradient,tension:0.4,pointRadius:0,pointHoverRadius:6}]},options:{responsive:true,maintainAspectRatio:false,scales:{y:{beginAtZero:false,grid:getCommonGridOptions(),ticks:{...getCommonTickOptions(),callback:(value)=>formatCurrency(value)}},x:{grid:{display:false},ticks:getCommonTickOptions()}},plugins:{legend:{display:false},tooltip:{...getCommonTooltipOptions(),mode:'index',intersect:false,callbacks:{label:(context)=>`${context.dataset.label}: ${formatCurrency(context.parsed.y)}`}}},interaction:{mode:'nearest',axis:'x',intersect:false}}});}
document.addEventListener('DOMContentLoaded',()=>{initGastosChart();initSavingsGrowthChart();initBudgetVsActualChart();initInversionesChart();});;